<?php
declare(strict_types=1);namespace App\Repositories\ControlEscaneres\Pdo;use App\Repositories\ControlEscaneres\Contracts\ScannerIncidentRepositoryInterface;use App\DTO\ControlEscaneres\ScannerIncidentCreateData;use App\Domain\ControlEscaneres\{ScannerIncident,IncidentStatus,IncidentSeverity};
final class PdoScannerIncidentRepository extends AbstractPdoRepository implements ScannerIncidentRepositoryInterface{private function map(array$r):ScannerIncident{return new ScannerIncident((int)$r['id'],new IncidentSeverity($r['severidad']),new IncidentStatus($r['estado']));}private function many(string$q,array$p=[]):array{return array_map(fn($r)=>$this->map($r),$this->stmt($q,$p)->fetchAll(\PDO::FETCH_ASSOC));}public function create(ScannerIncidentCreateData$d):ScannerIncident{$this->stmt("INSERT INTO scanner_incidencias(scanner_id,tipo,severidad,descripcion,estado,registrada_por,reportada_at)VALUES(:s,:t,:v,:d,'abierta',:u,:a)",['s'=>$d->scannerId,'t'=>$d->type,'v'=>$d->severity->value,'d'=>$d->description,'u'=>$d->actor->userId,'a'=>$d->reportedAt->format('Y-m-d H:i:s.u')]);return$this->findById((int)$this->pdo->lastInsertId());}public function findById(int$id):?ScannerIncident{$r=$this->stmt('SELECT * FROM scanner_incidencias WHERE id=:i',['i'=>$id])->fetch(\PDO::FETCH_ASSOC);return is_array($r)?$this->map($r):null;}public function listByScannerId(int$id):array{return$this->many('SELECT * FROM scanner_incidencias WHERE scanner_id=:i',['i'=>$id]);}public function listOpen():array{return$this->many("SELECT * FROM scanner_incidencias WHERE estado NOT IN('resuelta','descartada')");}public function changeStatus(int$id,IncidentStatus$s,int$u):void{$this->stmt('UPDATE scanner_incidencias SET estado=:s WHERE id=:i',['s'=>$s->value,'i'=>$id]);}public function resolve(int$id,string$r,int$u,\DateTimeImmutable$a):void{$this->stmt("UPDATE scanner_incidencias SET estado='resuelta',resolucion=:r,resuelta_por=:u,resuelta_at=:a WHERE id=:i",['r'=>$r,'u'=>$u,'a'=>$a->format('Y-m-d H:i:s.u'),'i'=>$id]);}public function countOpenBySeverity(IncidentSeverity$s):int{return(int)$this->stmt("SELECT COUNT(*) FROM scanner_incidencias WHERE severidad=:s AND estado NOT IN('resuelta','descartada')",['s'=>$s->value])->fetchColumn();}}
